import android.content.Context;
import android.content.SharedPreferences;
import android.util.Base64;
import android.util.Log;
import java.io.IOException;
import java.security.GeneralSecurityException;
import java.security.KeyStore;
import java.security.SecureRandom;
import java.security.cert.CertificateException;
import java.security.cert.X509Certificate;
import javax.net.ssl.SSLContext;
import javax.net.ssl.TrustManagerFactory;
import okhttp3.Interceptor;
import okhttp3.Request;
import okhttp3.Response;

public class LoginInterceptor implements Interceptor {
    private static final String TAG = "LoginInterceptor";
    private static final String PREFERENCES_NAME = "login_preferences";
    private static final String KEY_EMAIL = "email";
    private static final String KEY_AUTH_TOKEN = "auth_token";

    @Override
    public Response intercept(Chain chain) throws IOException {
        Request request = chain.request();

        // Get the SharedPreferences instance for this app
        SharedPreferences preferences = context.getSharedPreferences(PREFERENCES_NAME, Context.MODE_PRIVATE);

        // Check if there is a saved email and auth token
        String email = preferences.getString(KEY_EMAIL, null);
        String authToken = preferences.getString(KEY_AUTH_TOKEN, null);

        // If there is no saved email or auth token, proceed with the request as usual
        if (email == null || authToken == null) {
            return chain.proceed(request);
        }

        // Add the saved email and auth token to the request headers
        Request newRequest = request.newBuilder()
                .addHeader("Authorization", "Bearer " + authToken)
                .build();

        // Proceed with the modified request
        return chain.proceed(newRequest);
    }
}